import pytest
import time
from solution import rate_limit

def test_rate_limit_allows_within_limit():
    @rate_limit(max_calls=3, period=60)
    def f():
        return 'ok'
    assert f() == 'ok'
    assert f() == 'ok'
    assert f() == 'ok'

def test_rate_limit_blocks_when_exceeded():
    @rate_limit(max_calls=2, period=60)
    def f():
        return 'ok'
    f()
    f()
    with pytest.raises(RuntimeError):
        f()

def test_rate_limit_resets_after_period():
    @rate_limit(max_calls=1, period=1)
    def f():
        return 'ok'
    assert f() == 'ok'
    with pytest.raises(RuntimeError):
        f()
    time.sleep(1.1)
    assert f() == 'ok'

def test_rate_limit_preserves_function_metadata():
    @rate_limit(max_calls=5, period=60)
    def my_func():
        """My docstring."""
        return 'x'
    assert my_func.__name__ == 'my_func'
    assert my_func.__doc__ == 'My docstring.'
